from prometheus_client import start_http_server, Gauge
import time
import psycopg2

# Define Prometheus gauge metrics
db_connection_metric = Gauge('db_connection_health', 'Database connection health', ['username', 'password', 'host', 'connection_string'])

def check_db_connection(username, password, host, dbname):
    try:
        conn = psycopg2.connect(user=username, password=password, host=host, dbname=dbname)
        conn.close()
        return True
    except:
        return False

def monitor_db(username, password, host, dbname):
    connection_string = f"postgresql://{username}:{password}@{host}/{dbname}"
    while True:
        is_connected = check_db_connection(username, password, host, dbname)
        db_connection_metric.labels(username=username, password=password, host=host, connection_string=connection_string).set(1 if is_connected else 0)
        time.sleep(10)

